  5‚Üí
  6‚Üí  If we are using the Chrome engine, add the "chrome" class to the
  7‚Üí  body and defer image resizing to pure CSS. The Chrome engine can
  8‚Üí  handle image resizing on its own, but for older versions of WebView,
  9‚Üí  we do it here.
 10‚Üí
 11‚Üí  If we are resizing with JavaScript, we also account for the CSS zoom
 12‚Üí  level applied to the image. If an image is scaled with CSS zoom, the
 13‚Üí  dimensions given to us by the browser will not be scaled
 14‚Üí  accordingly, giving us only the original dimensions. We have to
 15‚Üí  fetch the zoom value and scale the dimensions with it before
 16‚Üí  checking if the image exceeds the window bounds.
 17‚Üí
 18‚Üí  If the WebView loads too early on Android <= 2.3 (which happens on
 19‚Üí  the first card or regularly with WebView switching enabled), then
 20‚Üí  the window dimensions returned to us are 0x0. In this case, we skip
 21‚Üí  image resizing and try again after we know the window has fully
 22‚Üí  loaded with a method call initiated from Java (onPageFinished).
 23‚Üí*/
 24‚Üívar resizeImages = function () {
 25‚Üí    if (navigator.userAgent.indexOf("Chrome") > -1) {
 26‚Üí        document.body.className = document.body.className + " chrome";
 27‚Üí    } else {
 28‚Üí        if (window.innerWidth === 0 || window.innerHeight === 0) {
 29‚Üí            return;
 30‚Üí        }
 31‚Üí        var maxWidth = window.innerWidth * 0.9;
 32‚Üí        var maxHeight = window.innerHeight * 0.9;
 33‚Üí        var ratio = 0;
 34‚Üí        var images = document.getElementsByTagName("img");
 35‚Üí        for (var i = 0; i < images.length; i++) {
 36‚Üí            var img = images[i];
 37‚Üí            var scale = 1;
 38‚Üí            var zoom = window.getComputedStyle(img).getPropertyValue("zoom");
 39‚Üí            if (!isNaN(zoom)) {
 40‚Üí                scale = zoom;
 41‚Üí            }
 42‚Üí            var width = img.width * scale;
 43‚Üí            var height = img.height * scale;
 44‚Üí            if (width > maxWidth) {
 45‚Üí                img.width = maxWidth;
 46‚Üí                img.height = height * (maxWidth / width);
 47‚Üí                width = img.width;
 48‚Üí                height = img.height;
 49‚Üí                img.style.zoom = 1;
 50‚Üí            }
 51‚Üí            if (height > maxHeight) {
 52‚Üí                img.width = width * (maxHeight / height);
 53‚Üí                img.height = maxHeight;
 54‚Üí                img.style.zoom = 1;
 55‚Üí            }
 56‚Üí        }
 57‚Üí    }
